class Logger {
  Logger._();                              // private constructor
  static final Logger _instance = Logger._();
  static Logger get instance => _instance;

  void info(String msg) => print('[INFO] $msg');
}

void main() {
  Logger.instance.info('app started');
  final a = Logger.instance;
  final b = Logger.instance;
  print(identical(a, b));   // true — same instance
}

abstract class Notification { void show(String msg); }
class EmailNotification    extends Notification { @override show(m) => print('email: $m'); }
class SmsNotification      extends Notification { @override show(m) => print('sms: $m'); }
class WhatsAppNotification extends Notification { @override show(m) => print('wa: $m'); }

// FACTORY
Notification notifyFor(String channel) {
  switch (channel) {
    case 'email':    return EmailNotification();
    case 'sms':      return SmsNotification();
    case 'whatsapp': return WhatsAppNotification();
    default: throw 'unknown';
  }
}

void main() {
  notifyFor('sms').show('OTP is 1234');   // caller doesn't know the class
}

class Counter {
  int _value = 0;
  final _observers = <void Function(int)>[];

  void listen(void Function(int) f) => _observers.add(f);
  void unlisten(void Function(int) f) => _observers.remove(f);

  int get value => _value;

  void increment() {
    _value++;
    for (final f in _observers) f(_value);      // notify
  }
}

void main() {
  final counter = Counter();
  counter.listen((v) => print('Screen 1: $v'));
  counter.listen((v) => print('Analytics: user reached $v'));

  counter.increment();   // both observers fire
  counter.increment();
  // Screen 1: 1
  // Analytics: user reached 1
  // Screen 1: 2
  // Analytics: user reached 2
}

// Strategy interface
abstract class PricingStrategy { double apply(double price); }

class NoDiscount     extends PricingStrategy { @override apply(p) => p; }
class PercentOff     extends PricingStrategy {
  final double pct;
  PercentOff(this.pct);
  @override apply(p) => p * (1 - pct/100);
}
class BuyOneGetOne   extends PricingStrategy { @override apply(p) => p / 2; }

class Cart {
  PricingStrategy strategy;
  Cart(this.strategy);
  double total(double price) => strategy.apply(price);
}

void main() {
  final cart = Cart(NoDiscount());
  print(cart.total(100));                       // 100
  cart.strategy = PercentOff(20);
  print(cart.total(100));                       // 80
  cart.strategy = BuyOneGetOne();
  print(cart.total(100));                       // 50
}

abstract class Coffee { double cost(); String description(); }

class SimpleCoffee extends Coffee {
  @override cost() => 5.0;
  @override description() => 'Coffee';
}

// DECORATOR — wraps a Coffee and adds behavior
abstract class CoffeeDecorator extends Coffee {
  final Coffee _wrapped;
  CoffeeDecorator(this._wrapped);
}

class Milk extends CoffeeDecorator {
  Milk(super.wrapped);
  @override cost() => _wrapped.cost() + 1.5;
  @override description() => '${_wrapped.description()}, milk';
}

class Sugar extends CoffeeDecorator {
  Sugar(super.wrapped);
  @override cost() => _wrapped.cost() + 0.5;
  @override description() => '${_wrapped.description()}, sugar';
}

void main() {
  final drink = Sugar(Milk(Milk(SimpleCoffee())));
  print(drink.description());   // Coffee, milk, milk, sugar
  print(drink.cost());          // 8.5
}
